class Solution:
    def appendCharacters(self, s, t):
        matched = 0
        for length in range(len(t), -1, -1):
            prefix = t[:length]
            i = 0
            for ch in s:
                if i < len(prefix) and ch == prefix[i]:
                    i += 1
            if i == len(prefix):
                matched = length
                break
        return len(t) - matched

